def read_int():
    return int(input())

def read_ints():
    return list(map(int, input().split(' ')))

def check_condition(a, b, c):
    return a < b < c

def is_divisible(a, b):
    return a % b == 0

def main():
    n = read_int()
    nums = read_ints()
    nums.sort()
    if n % 3 != 0:
        print(-1)
        return
    groups = []
    for i in range(0, n, 3):
        a, b, c = nums[i], nums[i+1], nums[i+2]
        if not check_condition(a, b, c):
            print(-1)
            return
        if not is_divisible(a, b) or not is_divisible(b, c):
            print(-1)
            return
        groups.append((a, b, c))
    for group in groups:
        print(*group)

if __name__ == '__main__':
    main()
